void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//initial textures:
//1. Main image
     vec3 base=texture(sampler_main, vUv);
//2. High quality noise sampler
     vec3 hinoise=texture(sampler_noise_hq, vUv);

//declaring modifying vars:
//1. Perspective UV value
     vec2 uvp=vUv;
     uvp.y*=.38;
//2. Blur values
     vec3 blpi=GetBlur1(uvp);
     vec3 blpii=GetBlur2(uvp);
     vec3 blpiii= GetBlur3(uvp);
     vec3 blmi=GetBlur1(vUv);
     vec3 blmii=GetBlur2(vUv);
     vec3 blmiii=GetBlur3(vUv);

//Perspective modified samplers
//1. Perspective Main
     vec3 pret=texture(sampler_main, uvp);

//final return value
vec3 fret=(1/blpii-(pret*blpi)).xyz;
fret-=blmii*1.35;

ret=1-fret*fret;
ret-=roam_sin.wzy*roam_cos.zxy;

  fragColor = ret;
}
